const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
if (!body.lead_id || !body.carrier_id || !body.client_id) return { json: { _empty: true, status: 400, error: 'lead_id, carrier_id, client_id required' } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','mga_principal','admin','supervisor'];
if (allowed.indexOf(row.user_role) === -1) return { json: { _unauthorized: true, status: 403, error: 'Advisor or higher required' } };
const b = $('Extract').item.json.body;
const payload = { vertical_id: 'insurance', client_id: b.client_id, lead_id: b.lead_id, carrier_id: b.carrier_id, product_id: b.product_id || null, suitability_assessment_id: b.suitability_assessment_id || null, quote_amount_cents: b.quote_amount_cents || null, quote_premium_monthly_cents: b.quote_premium_monthly_cents || null, quote_premium_annual_cents: b.quote_premium_annual_cents || null, quote_term_years: b.quote_term_years || null, quote_source: 'manual', quote_data: b.quote_data || {}, quote_received_at: new Date().toISOString(), quote_expires_at: b.quote_expires_at || null, status: 'received', created_by_user_id: row.id || row.user_id };
return { json: { _ok: true, payload, actor_id: row.id || row.user_id } };

const rows = $('Insert Quote').first().json;
const row  = Array.isArray(rows) ? (rows[0] || null) : rows;
return { json: { ok: true, quote: row } };
